<style scoped>
.orbit-ring {
	transform-origin: 261px 163px;
	animation: eco-orbit-cw 45s linear infinite;
}

/* counter-rotate each card so it stays upright */
.logo-meta {
	transform-origin: 157px 64px;
	animation: eco-orbit-ccw 45s linear infinite;
}

.logo-google {
	transform-origin: 120px 212px;
	animation: eco-orbit-ccw 45s linear infinite;
}

.logo-tiktok {
	transform-origin: 367px 65px;
	animation: eco-orbit-ccw 45s linear infinite;
}

.logo-x {
	transform-origin: 265px 277px;
	animation: eco-orbit-ccw 45s linear infinite;
}

.logo-snapchat {
	transform-origin: 403px 207px;
	animation: eco-orbit-ccw 45s linear infinite;
}

/* decorative dot pulse */
.dot {
	transform-box: fill-box;
	transform-origin: center;
	will-change: transform, opacity;
	backface-visibility: hidden;
	animation: eco-dot-pulse 3s ease-in-out infinite;
}

.dot-1 { animation-delay: 0s; }
.dot-2 { animation-delay: 0.6s; }
.dot-3 { animation-delay: 1.2s; }
.dot-4 { animation-delay: 1.8s; }
.dot-5 { animation-delay: 2.4s; }

@keyframes eco-orbit-cw {
	from { transform: rotate(0deg); }
	to { transform: rotate(360deg); }
}

@keyframes eco-orbit-ccw {
	from { transform: rotate(0deg); }
	to { transform: rotate(-360deg); }
}

@keyframes eco-dot-pulse {
	0%, 100% { opacity: 1; transform: scale(1); }
	50% { opacity: 0.4; transform: scale(0.55); }
}

@media (prefers-reduced-motion: reduce) {
	.orbit-ring,
	.logo-meta,
	.logo-google,
	.logo-tiktok,
	.logo-x,
	.logo-snapchat,
	.dot {
		animation: none;
	}
}
</style>
